use std::str::FromStr;

use kbonaci::BigInt;

#[test]
fn add_big_ints() {
    let a = BigInt::new(12345678901234567890);
    let b = BigInt::new(98765432109876543210);
    let c = a + b;
    assert_eq!(c.nums, vec![111111111011111111100]);

    let a = BigInt::new(1);
    let b = BigInt::new(1);
    assert_eq!((a + b).nums, vec![2]);

    let a = BigInt::new(u128::MAX);
    let b = BigInt::new(148189741429048);
    let c = a + b;
    assert_eq!(c.nums, vec![148189741429047, 1]);
}

#[test]
fn display_big_ints() {
    let a = BigInt::new(12345678901234567890);
    let b = BigInt::new(98765432109876543210);
    let c = a + b;
    assert_eq!(c.to_string(), "111111111011111111100");

    let a = BigInt::new(1);
    let b = BigInt::new(1);
    assert_eq!((a + b).to_string(), "2");

    let a = BigInt::new(u128::MAX);
    let b = BigInt::new(148189741429048);
    let c = a + b;
    assert_eq!(c.to_string(), "340282366920938463463374755621509640503");
}

#[test]
fn mul_big_ints() {
    let a = "";
    let b = "";
    assert_eq!((BigInt::from_str(a).unwrap() * BigInt::from_str(b).unwrap()).to_string(), (num_bigint::BigUint::from_str(a).unwrap() * num_bigint::BigUint::from_str(b).unwrap()).to_string());
    let a = "";
    let b = "";
    assert_eq!((BigInt::from_str(a).unwrap() * BigInt::from_str(b).unwrap()).to_string(), (num_bigint::BigUint::from_str(a).unwrap() * num_bigint::BigUint::from_str(b).unwrap()).to_string(), "karatsuba mul");
}

#[test]
fn cmp_big_ints() {
    let a = BigInt::new(12345678901234567890);
    let b = BigInt::new(98765432109876543210);
    let c = a < b;
    assert_eq!(c, true);

    let a = BigInt::new(1);
    let b = BigInt::new(1);
    assert_eq!(a < b, false);
    assert_eq!(a == b, true);
}

#[test]
fn interop_big_ints() {
    assert_eq!(
        BigInt::from_uint(num_bigint::BigUint::from(12345678901234567890u128)).to_string(),
        "12345678901234567890"
    );
    assert_eq!(BigInt::from_uint(num_bigint::BigUint::from_str("").unwrap()).to_string(), "");
}
